--
-- Name: enrich_company_v2(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enrich_company_v2(p jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_cik text := p->>'company_cik';
BEGIN
  IF v_cik IS NULL THEN
    RAISE EXCEPTION 'enrich_company_v2: company_cik required';
  END IF;

  -- 1. company row (upsert in case of re-enrichment)
  INSERT INTO companies(
    company_cik, name, ticker, exchanges, former_names,
    sic, sic_description, state_of_incorp, address, website,
    investor_website, fiscal_year_end, entity_type, filer_category
  )
  VALUES (
    v_cik,
    p->>'name',
    p->>'ticker',
    COALESCE(p->'exchanges', '[]'::jsonb),
    COALESCE(p->'former_names', '[]'::jsonb),
    p->>'sic',
    p->>'sic_description',
    p->>'state_of_incorp',
    p->>'address',
    p->>'website',
    p->>'investor_website',
    p->>'fiscal_year_end',
    p->>'entity_type',
    p->>'filer_category'
  )
  ON CONFLICT (company_cik) DO UPDATE SET
    name              = EXCLUDED.name,
    ticker            = EXCLUDED.ticker,
    exchanges         = EXCLUDED.exchanges,
    former_names      = EXCLUDED.former_names,
    sic               = EXCLUDED.sic,
    sic_description   = EXCLUDED.sic_description,
    state_of_incorp   = EXCLUDED.state_of_incorp,
    address           = EXCLUDED.address,
    website           = EXCLUDED.website,
    investor_website  = EXCLUDED.investor_website,
    fiscal_year_end   = EXCLUDED.fiscal_year_end,
    entity_type       = EXCLUDED.entity_type,
    filer_category    = EXCLUDED.filer_category;

  -- 2. bulk-insert filings (n8n applies SCRAPE_LIST + 3yr filter before sending)
  INSERT INTO company_filings(company_cik, accession, form, filing_date, items)
  SELECT
    v_cik,
    f.accession,
    f.form,
    f.filing_date,
    f.items
  FROM jsonb_to_recordset(COALESCE(p->'filings', '[]'::jsonb))
    AS f(accession text, form text, filing_date date, items text)
  WHERE f.accession IS NOT NULL AND f.filing_date IS NOT NULL
  ON CONFLICT (company_cik, accession) DO NOTHING;

  -- 3. flip enriched flag
  UPDATE cik_list SET enriched = TRUE WHERE cik = v_cik;
END;
$$;


--
-- Name: enrich_entity(jsonb, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enrich_entity(p jsonb, kind text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF kind = 'company' THEN
    PERFORM enrich_company_v2(p);
  ELSIF kind = 'person' THEN
    PERFORM enrich_person_v2(p);
  ELSE
    RAISE EXCEPTION 'enrich_entity: kind must be "company" or "person", got %', kind;
  END IF;
END;
$$;


--
-- Name: enrich_person_v2(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enrich_person_v2(p jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_cik text := p->>'person_cik';
BEGIN
  IF v_cik IS NULL THEN
    RAISE EXCEPTION 'enrich_person_v2: person_cik required';
  END IF;

  -- 1. person row (upsert)
  INSERT INTO people(person_cik, canonical_name, former_names, address, entity_type)
  VALUES (
    v_cik,
    p->>'canonical_name',
    COALESCE(p->'former_names', '[]'::jsonb),
    p->>'address',
    p->>'entity_type'
  )
  ON CONFLICT (person_cik) DO UPDATE SET
    canonical_name = EXCLUDED.canonical_name,
    former_names   = EXCLUDED.former_names,
    address        = EXCLUDED.address,
    entity_type    = EXCLUDED.entity_type;

  -- 2. bulk-insert filings
  INSERT INTO people_filings(person_cik, accession, form, filing_date)
  SELECT
    v_cik,
    f.accession,
    f.form,
    f.filing_date
  FROM jsonb_to_recordset(COALESCE(p->'filings', '[]'::jsonb))
    AS f(accession text, form text, filing_date date)
  WHERE f.accession IS NOT NULL AND f.filing_date IS NOT NULL
  ON CONFLICT (person_cik, accession) DO NOTHING;

  -- 3. flip enriched flag
  UPDATE cik_list SET enriched = TRUE WHERE cik = v_cik;
END;
$$;


--
-- Name: import_entity_filings(text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.import_entity_filings(p_cik text, p_sub jsonb) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_is_company boolean;
  v_is_person  boolean;
  v_scrape     text[];
  v_recent     jsonb := p_sub->'filings'->'recent';
  v_n          int;
  v_inserted   int := 0;
BEGIN
  IF v_recent IS NULL OR jsonb_typeof(v_recent->'accessionNumber') <> 'array' THEN
    RETURN 0;
  END IF;

  SELECT EXISTS (SELECT 1 FROM companies WHERE company_cik = p_cik) INTO v_is_company;
  SELECT EXISTS (SELECT 1 FROM people    WHERE person_cik  = p_cik) INTO v_is_person;
  IF NOT (v_is_company OR v_is_person) THEN
    RETURN 0;
  END IF;

  SELECT array_agg(form) INTO v_scrape FROM forms;
  v_n := jsonb_array_length(v_recent->'accessionNumber');
  IF v_n = 0 THEN RETURN 0; END IF;

  WITH zipped AS (
    SELECT
      (v_recent->'accessionNumber'->>i)::text AS accession,
      (v_recent->'form'->>i)::text             AS form,
      (v_recent->'filingDate'->>i)::text       AS filing_date,
      COALESCE(v_recent->'items'->>i,'')::text AS items
    FROM generate_series(0, v_n - 1) AS i
  ),
  filtered AS (
    SELECT accession, form, filing_date::date AS filing_date, NULLIF(items,'') AS items
    FROM zipped
    WHERE accession IS NOT NULL AND accession <> ''
      AND form = ANY(v_scrape)
      AND filing_date <> ''
      AND filing_date::date >= current_date - interval '3 years'
  ),
  ins_c AS (
    INSERT INTO company_filings (company_cik, accession, form, filing_date, items)
    SELECT p_cik, accession, form, filing_date, items FROM filtered
    WHERE v_is_company
    ON CONFLICT (company_cik, accession) DO NOTHING
    RETURNING 1
  ),
  ins_p AS (
    INSERT INTO people_filings (person_cik, accession, form, filing_date)
    SELECT p_cik, accession, form, filing_date FROM filtered
    WHERE v_is_person
    ON CONFLICT (person_cik, accession) DO NOTHING
    RETURNING 1
  )
  SELECT (SELECT count(*) FROM ins_c) + (SELECT count(*) FROM ins_p) INTO v_inserted;

  RETURN v_inserted;
END;
$$;


