-- Name: ingest_signal(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ingest_signal(p jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $_$
DECLARE
  v_accession  text := p->>'accession';
  v_form_type  text := p->>'form_type';
  v_table      text;
  v_payload    jsonb;
  v_cik        record;
BEGIN
  IF v_accession IS NULL OR v_form_type IS NULL THEN
    RAISE EXCEPTION 'ingest_signal: accession and form_type required';
  END IF;

  INSERT INTO signals(accession, form_type, date_added)
  VALUES (v_accession, v_form_type, now())
  ON CONFLICT (accession) DO NOTHING;

  v_table := CASE v_form_type
    WHEN '3'        THEN 'form_3'
    WHEN '3/A'      THEN 'form_3'
    WHEN '4'        THEN 'form_4'
    WHEN '4/A'      THEN 'form_4_a'
    WHEN '5'        THEN 'form_5'
    WHEN '5/A'      THEN 'form_5'
    WHEN 'D'        THEN 'form_d_a'
    WHEN 'D/A'      THEN 'form_d_a'
    WHEN 'C'        THEN 'form_c'
    WHEN 'C/A'      THEN 'form_c_a'
    WHEN '8-K'      THEN 'form_8_k'
    WHEN '10-Q'     THEN 'form_10_q'
    WHEN 'S-1'      THEN 'form_s_1'
    WHEN 'S-1/A'    THEN 'form_s_1_a'
    WHEN 'S-3'      THEN 'form_s_3'
    WHEN 'DEF 14A'  THEN 'form_def_14a'
    WHEN '13F-HR'   THEN 'form_13f_hr'
    WHEN '13F-NT'   THEN 'form_13f_nt'
    WHEN '144'      THEN 'form_144'
    WHEN '144/A'    THEN 'form_144_a'
    WHEN 'N-CEN'    THEN 'form_n_cen'
    WHEN 'N-PX'     THEN 'form_n_px'
    WHEN 'N-PORT'   THEN 'form_n_port'
    WHEN 'N-14'     THEN 'form_n_14'
    WHEN '40-APP'   THEN 'form_40_app'
    WHEN '425'      THEN 'form_425'
    WHEN 'FWP'      THEN 'form_fwp'
    WHEN '424B5'    THEN 'form_424b5'
    WHEN 'SC 13D'   THEN 'form_sc_13d'
    WHEN 'SC 13G'   THEN 'form_sc_13g'
    ELSE NULL
  END;

  IF v_table IS NULL THEN
    RAISE EXCEPTION 'ingest_signal: unknown form_type %', v_form_type;
  END IF;

  v_payload := p - 'ciks';

  EXECUTE format(
    'INSERT INTO %1$I SELECT (jsonb_populate_record(NULL::%1$I, $1)).* ON CONFLICT (accession) DO NOTHING',
    v_table
  ) USING v_payload;

  FOR v_cik IN
    SELECT DISTINCT cik FROM jsonb_to_recordset(p->'ciks') AS x(cik text, role text)
    WHERE cik IS NOT NULL
  LOOP
    INSERT INTO cik_list(cik, date_added, enriched)
    VALUES (v_cik.cik, now(), FALSE)
    ON CONFLICT (cik) DO NOTHING;
  END LOOP;

  INSERT INTO signal_ciks(accession, cik, cik_role)
  SELECT v_accession, x.cik, x.role
  FROM jsonb_to_recordset(p->'ciks') AS x(cik text, role text)
  WHERE x.cik IS NOT NULL AND x.role IS NOT NULL
  ON CONFLICT (accession, cik, cik_role) DO NOTHING;
END;
$_$;


--
-- Name: ingest_signals_bulk(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ingest_signals_bulk(p jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_item    jsonb;
  v_ok      int    := 0;
  v_err     int    := 0;
  v_errors  jsonb  := '[]'::jsonb;
BEGIN
  IF jsonb_typeof(p) <> 'array' THEN
    RAISE EXCEPTION 'ingest_signals_bulk: p must be a jsonb array, got %', jsonb_typeof(p);
  END IF;

  FOR v_item IN SELECT jsonb_array_elements(p) LOOP
    BEGIN
      PERFORM ingest_signal(v_item);
      v_ok := v_ok + 1;
    EXCEPTION WHEN OTHERS THEN
      v_err := v_err + 1;
      v_errors := v_errors || jsonb_build_object(
        'accession', v_item->>'accession',
        'form_type', v_item->>'form_type',
        'sqlstate',  SQLSTATE,
        'error',     SQLERRM
      );
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'ok',     v_ok,
    'err',    v_err,
    'errors', v_errors
  );
END;
$$;


--
-- Name: refresh_forms_counts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_forms_counts() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- filings_count = signals per form_type
  UPDATE forms f SET filings_count = COALESCE(s.cnt, 0)
  FROM (
    SELECT form_type, count(*) AS cnt FROM signals GROUP BY form_type
  ) s
  WHERE f.form = s.form_type;

  -- form_types not in signals → 0
  UPDATE forms f SET filings_count = 0
  WHERE NOT EXISTS (SELECT 1 FROM signals s WHERE s.form_type = f.form);

  -- companies_count = distinct company_cik linked to any signal of this form_type
  UPDATE forms f SET companies_count = COALESCE(s.cnt, 0)
  FROM (
    SELECT s.form_type, count(DISTINCT c.company_cik) AS cnt
    FROM signals s
    JOIN signal_ciks sc ON sc.accession = s.accession
    JOIN companies c    ON c.company_cik = sc.cik
    GROUP BY s.form_type
  ) s
  WHERE f.form = s.form_type;

  UPDATE forms f SET companies_count = 0
  WHERE NOT EXISTS (
    SELECT 1 FROM signals s
    JOIN signal_ciks sc ON sc.accession = s.accession
    JOIN companies c    ON c.company_cik = sc.cik
    WHERE s.form_type = f.form
  );
END;
$$;


